import React, { useState } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

// --- INTEGRATED WIG STORE (With Educational Notes) ---
const WigStore = () => {
  const gold = '#D4AF37';
  const fancyFont = "'Playfair Display', 'Georgia', serif";

  const categories = [
    {
      type: "Human Hair",
      note: "The Gold Standard. 100% authentic hair that can be bleached, dyed, and heat-styled. Offers the most natural movement and lasts for years.",
      items: [
        { name: "Luxury Raw Cambodian", price: "85,000", desc: "14-inch frontal unit. Natural luster and premium bounce." }
      ]
    },
    {
      type: "Premium Fibre",
      note: "High-heat resistant synthetic blend that perfectly mimics human hair. Pre-styled, holds its shape, and is the ultimate 'ready-to-go' luxury.",
      items: [
        { name: "Sleek Bone Straight", price: "35,000", desc: "Heat resistant up to 180°C. Perfect glass-hair shine." }
      ]
    },
    {
      type: "Hair Blend",
      note: "The best of both worlds. A strategic mix of human hair and premium fibres. Durable, affordable, and holds curls longer than pure human hair.",
      items: [
        { name: "Piano Wavy T-Closure", price: "25,000", desc: "24-inch body wave. High-octane volume and piano highlights." }
      ]
    }
  ];

  return (
    <div style={{ color: '#fff' }}>
      {categories.map((cat) => (
        <div key={cat.type} style={{ marginBottom: '80px' }}>
          
          {/* Educational Note */}
          <div style={{ borderLeft: `4px solid ${gold}`, padding: '15px 30px', backgroundColor: '#0A0A0A', marginBottom: '30px' }}>
            <h3 style={{ color: gold, fontFamily: fancyFont, fontSize: '1.8rem', margin: '0 0 10px 0' }}>{cat.type}</h3>
            <p style={{ color: '#888', fontStyle: 'italic', fontSize: '0.9rem', lineHeight: '1.5' }}>"{cat.note}"</p>
          </div>

          {/* Product Grid */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '30px' }}>
            {cat.items.map((item) => (
              <div key={item.name} style={{ border: `1px solid #1a1a1a`, padding: '20px', textAlign: 'center', backgroundColor: '#050505' }}>
                <h4 style={{ color: gold, fontFamily: fancyFont, fontSize: '1.3rem' }}>{item.name}</h4>
                <p style={{ color: '#555', fontSize: '0.8rem', margin: '10px 0' }}>{item.desc}</p>
                <div style={{ color: gold, fontWeight: 'bold', fontSize: '1.2rem', marginBottom: '15px' }}>₦{item.price}</div>
                <button style={{ background: 'none', border: `1px solid ${gold}`, color: gold, padding: '8px 20px', cursor: 'pointer', fontSize: '0.7rem', letterSpacing: '1px' }}>
                  ORDER ON WHATSAPP
                </button>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

// --- MAIN APP COMPONENT ---
function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const gold = '#D4AF37';
  const fancyFont = "'Playfair Display', 'Georgia', serif";

  const headerStyle = {
    color: gold, textAlign: 'center', fontSize: '3rem', marginBottom: '50px',
    fontWeight: '400', fontFamily: fancyFont, letterSpacing: '3px', fontStyle: 'italic'
  };

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'Arial, sans-serif' }}>
      
      {/* NAVIGATION */}
      <nav style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '40px 20px', borderBottom: '1px solid #111' }}>
        <img src={Logo} alt="Logo" style={{ height: '100px', marginBottom: '30px' }} />
        <div style={{ display: 'flex', gap: '30px', flexWrap: 'wrap', justifyContent: 'center' }}>
          {['Small Chops', 'Office Lunch', 'Wigs', 'About Us'].map((item) => (
            <button 
              key={item} 
              onClick={() => setActiveCategory(item)}
              style={{ 
                background: 'none', border: 'none', color: gold, fontSize: '0.8rem', cursor: 'pointer',
                letterSpacing: '2px', textTransform: 'uppercase', paddingBottom: '5px',
                borderBottom: activeCategory === item ? `2px solid ${gold}` : '2px solid transparent',
                opacity: activeCategory === item ? 1 : 0.5
              }}
            >
              {item}
            </button>
          ))}
        </div>
      </nav>

      {/* CONTENT AREA */}
      <main style={{ padding: '50px 20px', maxWidth: '1100px', margin: '0 auto' }}>
        
        {activeCategory === 'Small Chops' && (
          <div key="chops">
            <h2 style={headerStyle}>Small Chops Curates</h2>
            <Menu />
          </div>
        )}

        {activeCategory === 'Office Lunch' && (
          <div key="lunch">
            <h2 style={headerStyle}>The Office Lunch</h2>
            <Lunch />
          </div>
        )}

        {activeCategory === 'Wigs' && (
          <div key="wigs">
            <h2 style={headerStyle}>The Hair Edit</h2>
            <WigStore />
          </div>
        )}

        {activeCategory === 'About Us' && (
          <div style={{ textAlign: 'center', padding: '40px' }}>
            <h2 style={headerStyle}>Our Story</h2>
            <p style={{ color: gold, opacity: 0.7, lineHeight: '2' }}>
              Àmí by T: Redefining luxury through taste and style.
            </p>
          </div>
        )}
      </main>

    </div>
  );
}

export default App;
